1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const DEDUCTIBLE = 100;
5	
6	const INSURANCE_VALUES: Record<string, number> = {
7	  sword: 1000,
8	  amulet: 600,
9	  staff: 800,
10	  potion: 400,
11	  rune: 250,
12	  moonstone: 250,
13	};
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	
26	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
27	
28	const basePremium = (item: any): number =>
29	  BASE_PREMIUMS[item.type] ?? 0;
30	
31	const groupByType = (items: any[]): Record<string, number> =>
32	  items.reduce(
33	    (counts: Record<string, number>, item: any) => ({
34	      ...counts,
35	      [item.type]: (counts[item.type] ?? 0) + 1,
36	    }),
37	    {},
38	  );
39	
40	const componentGroupPremium = (type: string, count: number): number =>
41	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
42	
43	const itemSurcharges = (item: any, base: number): number =>
44	  (item.cursed ? base * 0.5 : 0) + (item.enchantment >= 5 ? base * 0.3 : 0);
45	
46	const quotePremium = (items: any[], customer: any, quoteIndex: number): number => {
47	  const components = items.filter(isComponent);
48	  const nonComponents = items.filter((item: any) => !isComponent(item));
49	  const componentTotal = Object.entries(groupByType(components)).reduce(
50	    (sum: number, [type, count]: [string, number]) => sum + componentGroupPremium(type, count),
51	    0,
52	  );
53	  const { base: nonComponentBase, surcharges: surchargesTotal } = nonComponents.reduce(
54	    (acc, item: any) => {
55	      const b = basePremium(item);
56	      return { base: acc.base + b, surcharges: acc.surcharges + itemSurcharges(item, b) };
57	    },
58	    { base: 0, surcharges: 0 },
59	  );
60	  const policyBasePremium = nonComponentBase + componentTotal;
61	  const firstInsurance = policyBasePremium * 0.1;
62	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? -policyBasePremium * 0.2 : 0;
63	  const followUpDiscount = quoteIndex > 0 ? -policyBasePremium * 0.15 : 0;
64	  return Math.ceil(policyBasePremium + surchargesTotal + firstInsurance + loyaltyDiscount + followUpDiscount + PROCESSING_FEE);
65	};
66	
67	const insuranceSum = (items: any[]): number =>
68	  items.reduce((sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
69	
70	const processClaim = (step: any, policy: any): any => {
71	  const totalInsurance = insuranceSum(policy.items);
72	  const cap = totalInsurance * 2;
73	  const totalPayout = step.incident.damages.reduce(
74	    (sum: number, damage: any) => sum + Math.max(0, damage.amount - DEDUCTIBLE),
75	    0,
76	  );
77	  const clampedPayout = Math.min(totalPayout, cap);
78	  return { payout: Math.floor(clampedPayout), remainingCap: cap - clampedPayout };
79	};
80	
81	export const processScenario = (scenario: any): any => {
82	  const policies: Record<number, any> = {};
83	  let quoteIndex = 0;
84	  return {
85	    results: scenario.steps.map((step: any, index: number) => {
86	      if (step.op === "claim") {
87	        return processClaim(step, policies[step.policy]);
88	      }
89	      policies[index] = step;
90	      const result = { premium: quotePremium(step.items, scenario.customer, quoteIndex) };
91	      quoteIndex++;
92	      return result;
93	    }),
94	  };
95	};
